# Remove keystore-vol volumeMount at index 2 from elasticsearch container, then keystore-vol volume at index 0
# Must remove volumeMount first (higher index operations first to preserve indices)
kubectl patch statefulset es-cluster -n elasticsearch --type=json -p='[
  {"op": "remove", "path": "/spec/template/spec/containers/0/volumeMounts/2"},
  {"op": "remove", "path": "/spec/template/spec/volumes/0"}
]' 2>&1

