kubectl patch statefulset es-cluster -n elasticsearch --type=json -p='[
  {"op": "remove", "path": "/spec/template/spec/initContainers/1/volumeMounts/1"}
]' 2>&1

# Build a clean JSON patch:
# 1. Replace setup-keystore init container's volumeMounts and script
# 2. Replace config-vol mount (at index 0) in elasticsearch container with keystore-staging subPath mount
# 3. Replace config-vol volume with keystore-staging volume

kubectl patch statefulset es-cluster -n elasticsearch --type=json -p='[
  {
    "op": "replace",
    "path": "/spec/template/spec/initContainers/1/args",
    "value": [
      "set -e\nmkdir -p /tmp/ks\nexport ES_PATH_CONF=/tmp/ks\n/usr/share/elasticsearch/bin/elasticsearch-keystore create\ncat /mnt/secure-settings/s3.client.default.access_key | tr -d '\''\n'\'' | /usr/share/elasticsearch/bin/elasticsearch-keystore add --stdin s3.client.default.access_key\ncat /mnt/secure-settings/s3.client.default.secret_key | tr -d '\''\n'\'' | /usr/share/elasticsearch/bin/elasticsearch-keystore add --stdin s3.client.default.secret_key\necho -n \"elasticpass\" | /usr/share/elasticsearch/bin/elasticsearch-keystore add --stdin bootstrap.password\ncp /tmp/ks/elasticsearch.keystore /keystore-staging/elasticsearch.keystore\n"
    ]
  },
  {
    "op": "replace",
    "path": "/spec/template/spec/initContainers/1/volumeMounts/0",
    "value": {"name": "keystore-staging", "mountPath": "/keystore-staging"}
  },
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/volumeMounts/0",
    "value": {"name": "keystore-staging", "mountPath": "/usr/share/elasticsearch/config/elasticsearch.keystore", "subPath": "elasticsearch.keystore"}
  },
  {
    "op": "replace",
    "path": "/spec/template/spec/volumes/9",
    "value": {"name": "keystore-staging", "emptyDir": {}}
  }
]' 2>&1

kubectl exec -n elasticsearch es-cluster-0 -c elasticsearch -- curl -sk -u elastic:elasticpass \
